    .clock        (clock),
    .reset        (reset),
    .io_enq_valid (_GEN_3 & _recvFifo_io_count != 5'h10),
    .io_enq_bits  (~_GEN_3 | _GEN_2 ? 8'h0 : tsr),
    .io_deq_ready (recvPop | rxFlush),
    .io_deq_valid (_recvFifo_io_deq_valid),
    .io_deq_bits  (_recvFifo_io_deq_bits),
    .io_count     (_recvFifo_io_count)
  );
  Queue16_UInt8 xmitFifo (
    .clock        (clock),
    .reset        (reset),
    .io_enq_valid (out_f_woready & ~(lcr[7]) & fcrSticky[0]),
    .io_enq_bits
      (~out_f_woready | lcr[7] | ~(fcrSticky[0])
         ? 8'h0
         : _axi4buf_auto_out_w_bits_data[7:0]),
    .io_deq_ready (_GEN | _GEN_0 | txFlush),
    .io_deq_valid (_xmitFifo_io_deq_valid),
    .io_deq_bits  (_xmitFifo_io_deq_bits),
    .io_count     (_xmitFifo_io_count)
  );
  Queue2_RegMapperOutput out_deq_q (
    .clock                      (clock),
    .reset                      (reset),
    .io_enq_ready               (_out_deq_q_io_enq_ready),
    .io_enq_valid               (in_valid),
    .io_enq_bits_read           (_axi4buf_auto_out_ar_valid),
    .io_enq_bits_data           ({24'h0, _GEN_10[addr]}),
    .io_enq_bits_extra_extra_id
      (_axi4buf_auto_out_ar_valid
         ? _axi4buf_auto_out_ar_bits_id
         : _axi4buf_auto_out_aw_bits_id),
    .io_deq_ready
      (_out_deq_q_io_deq_bits_read
         ? _axi4buf_auto_out_r_ready
         : _axi4buf_auto_out_b_ready),
    .io_deq_valid               (_out_deq_q_io_deq_valid),
    .io_deq_bits_read           (_out_deq_q_io_deq_bits_read),
    .io_deq_bits_data           (_out_deq_q_io_deq_bits_data),
    .io_deq_bits_extra_extra_id (_out_deq_q_io_deq_bits_extra_extra_id)
  );
  assign io_uart_out_valid = txFire;
  assign io_uart_out_ch = tsr;
endmodule

